async (page) => {
  await page.waitForTimeout(15000);
  // Try warp after being away from mobs
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const s = JSON.parse(state);
  return JSON.stringify({pos: s.player_position, hp: `${s.player_stats.hp}/${s.player_stats.max_hp}`, nav: s.navigation.status, chat: s.ui_state.recent_chat.slice(0,3)});
}

