async (page) => {
  // Reset stuck state
  await page.evaluate(() => window.__stuckReset && window.__stuckReset());
  // Wait 12s for combat cooldown
  await page.waitForTimeout(12000);
  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const s = JSON.parse(state);
  return JSON.stringify({pos: s.player_position, hp: `${s.player_stats.hp}/${s.player_stats.max_hp}`, level: s.player_stats.level, chat: s.ui_state.recent_chat.slice(0,2)});
}

async (page) => {
  await page.waitForTimeout(30000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const s = JSON.parse(state);
  // Try warp now that we're away
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);
  const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const s2 = JSON.parse(state2);
  return JSON.stringify({pos: s.player_position, pos_after: s2.player_position, hp: `${s2.player_stats.hp}/${s2.player_stats.max_hp}`, nav: s2.navigation.status, chat: s2.ui_state.recent_chat.slice(0,1)});
}

